SELECT COUNT(DISTINCT S.PK_SIAPE) AS QUANTIDADE FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON S.PK_SIAPE = C.SIAPE WHERE LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(C.SIGLA_CAMPUS) = LOWER('inh') AND C.ANO = 2022 AND C.SEMESTRE = 2 AND LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%educacao fisica%'